#!/usr/bin/env bash
# Compute cumulative hand-written site source line deltas per release tag.
# "Hand-written" = everything inside site/ except:
#   - node_modules/  (deps)
#   - dist/          (compiled output)
#   - .astro/        (Astro cache)
#   - reports/       (audit outputs)
#   - package-lock.json (auto-generated)
#   - src/data/menus.json (auto-generated by fetch_data.py)
#   - public/*.png (binary assets — git diff --stat counts them as 0 anyway)
#
# Output: benchmark/data/site_lines.json
#   { "v0.1.2": {"insertions": N, "deletions": N, "lines_delta": N}, ... }
#
# v0.1.1 is treated as the *initial commit window* (full repo at that tag);
# every subsequent tag is the incremental diff vs the previous tag.

set -uo pipefail

ROOT="$(cd "$(dirname "$0")/../.." && pwd)"
OUT="$ROOT/benchmark/data/site_lines.json"
TAGS=(v0.1.1 v0.1.2 v0.1.3 v0.1.4 v0.1.5 v1.5.0 v1.6.0 v1.7.0)

EXCL=(
  ":(exclude)site/node_modules"
  ":(exclude)site/dist"
  ":(exclude)site/.astro"
  ":(exclude)site/reports"
  ":(exclude)site/package-lock.json"
  ":(exclude)site/src/data/menus.json"
)
INCL=( "site/" )

# Helper: extract "X insertions, Y deletions" from `git diff --stat | tail -1`
parse_delta() {
  local summary="$1"
  local ins del
  ins=$(echo "$summary" | grep -oE '[0-9]+ insertion' | grep -oE '[0-9]+' || echo 0)
  del=$(echo "$summary" | grep -oE '[0-9]+ deletion'  | grep -oE '[0-9]+' || echo 0)
  ins=${ins:-0}
  del=${del:-0}
  echo "$ins $del"
}

mkdir -p "$(dirname "$OUT")"
echo "{" > "$OUT.tmp"
first=1

# v0.1.1 baseline: diff from the empty tree to v0.1.1 (= every line added at first release)
empty_tree=$(git -C "$ROOT" hash-object -t tree --stdin < /dev/null 2>/dev/null \
              || git -C "$ROOT" rev-parse 4b825dc642cb6eb9a060e54bf8d69288fbee4904)
echo
echo ">>> v0.1.1 (baseline vs empty tree)"
summary=$(git -C "$ROOT" diff --shortstat "$empty_tree" v0.1.1 -- "${INCL[@]}" "${EXCL[@]}" 2>/dev/null)
read -r ins del <<< "$(parse_delta "$summary")"
total=$((ins + del))
echo "    insertions=$ins  deletions=$del  total=$total"
printf '  "v0.1.1": { "insertions": %d, "deletions": %d, "lines_delta": %d }' \
       "$ins" "$del" "$total" >> "$OUT.tmp"
first=0

for ((i = 1; i < ${#TAGS[@]}; i++)); do
  prev="${TAGS[$((i-1))]}"
  curr="${TAGS[$i]}"
  echo
  echo ">>> $curr (vs $prev)"
  summary=$(git -C "$ROOT" diff --shortstat "$prev..$curr" -- "${INCL[@]}" "${EXCL[@]}" 2>/dev/null)
  read -r ins del <<< "$(parse_delta "$summary")"
  total=$((ins + del))
  echo "    insertions=$ins  deletions=$del  total=$total"
  printf ',\n  "%s": { "insertions": %d, "deletions": %d, "lines_delta": %d }' \
         "$curr" "$ins" "$del" "$total" >> "$OUT.tmp"
done

printf '\n}\n' >> "$OUT.tmp"
mv "$OUT.tmp" "$OUT"

echo
echo "=== site/ hand-written line deltas per tag ==="
cat "$OUT"
